var e=[{id:`L2_1`,type:`dialog`,speaker:`CINDY_VATICAN_NULL_PR`,text:{KOREA:`그거 알아? 호러 영화에서는 가장 먼저 내빼는 놈이 가장 먼저 뒈지기 마련이거든.`,JPN:`知ってる？　ホラー映画では真っ先に逃げるやつが最初にくたばるもんなんだよ。`,ENG:`You know what? In horror movies, the one who runs away first is usually the first to die.`,TWN:`你知道嗎？恐怖片裡，通常最先逃跑的人死得最快。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CINDY_VATICAN_NULL_PR`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`CINDY_VATICAN_NULL_PR`,text:{KOREA:`하지만 걱정 마. 우리 사이에 이 계약이 존재하는 한, 나는 쭉 당신 곁을 지킬 테니까.`,JPN:`でも大丈夫。アタシたちの間にこの契約がある限り、アタシがずっとそばで守ってあげるから。`,ENG:`But don’t worry. As long as this contract exists between us, I’ll stay by your side.`,TWN:`但別擔心，在我們的契約期間，我都會一直在你身邊保護你。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CINDY_VATICAN_NULL_PR`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};